void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("Pablo_1");			link.l1 = StringFromKey("Pablo_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("Pablo_3");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "2";		break;		case "2":			dialog.text = StringFromKey("Pablo_4");			link.l1 = StringFromKey("Pablo_5");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("Pablo_6");			link.l1 = StringFromKey("Pablo_7");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("Pablo_8");			link.l1 = StringFromKey("Pablo_9");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("Pablo_10");			link.l1 = "...";			link.l1.go = "exit";			AddDialogExitQuest("MainHeroFightModeOn");		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}